1. AND Gate.rtl:
module and_gate(
    input a,
    input b,
    output y
);
    assign y = a & b;
endmodule

1. AND Gate.tb:
`timescale 1ns/1ps
module tb_and_gate;
    reg a, b;
    wire y;

    and_gate uut (
        .a(a),
        .b(b),
        .y(y)
    );

    initial begin
        a = 0; b = 0; #10;
        a = 0; b = 1; #10;
        a = 1; b = 0; #10;
        a = 1; b = 1; #10;
        $finish;
    end
endmodule

