17. 4:1 Multiplexer.rtl:
module mux4(
    input [3:0] i,
    input [1:0] sel,
    output y
);
    assign y = i[sel];
endmodule

17. 4:1 Multiplexer.tb:
`timescale 1ns/1ps
module tb_mux4;
    reg [3:0] i;
    reg [1:0] sel;
    wire y;

    mux4 uut (
        .i(i),
        .sel(sel),
        .y(y)
    );

    initial begin
        i = 4'h5555_5555_5555_5555 & ((4'd1 << 3) - 1);
        sel = 0;
        #10;
        repeat (4) begin
            #10 sel = sel + 1;
        end
        #10;
        i = ~i;
        sel = 0;
        repeat (4) begin
            #10 sel = sel + 1;
        end
        #10;
        $finish;
    end
endmodule

