43. 8-bit ALU.rtl:
module alu8(input [7:0] a, input [7:0] b, input [2:0] op, output reg [7:0] y);
    always @(*) begin
        case(op)
            3'b000: y = a + b;
            3'b001: y = a - b;
            3'b010: y = a & b;
            3'b011: y = a | b;
            3'b100: y = a ^ b;
            3'b101: y = ~(a & b);
            3'b110: y = a << 1;
            3'b111: y = a >> 1;
        endcase
    end
endmodule

