    always @(posedge clk) begin
        case(mode)
            2'b00: q <= q;
            2'b01: q <= {q[2:0], 1'b0};
            2'b10: q <= {1'b0, q[3:1]};
            2'b11: q <= d;
        endcase
    end
endmodule

