    always #5 clk = ~clk;
    initial begin
        clk = 0; mode = 2'b11; d = 4'b1011; #12;
        mode = 2'b01; #20;
        mode = 2'b10; #20;
        mode = 2'b00; #10;
        $finish;
    end
endmodule

