85. Moore 101 Detector (Overlapping).rtl:
module detector_101_moore_overlap(
    input clk,
    input rst,
    input din,
    output reg q_out
);
    localparam S0 = 2'd0;
    localparam S1 = 2'd1;
    localparam S2 = 2'd2;
    localparam S3 = 2'd3;

    reg [1:0] state_reg, state_next;

    // State Register
    always @(posedge clk or posedge rst) begin
        if (rst) state_reg <= S0;
        else     state_reg <= state_next;
    end

    // Next State Logic
    always @(*) begin
        state_next = state_reg;
        case (state_reg)
            S0: begin
                if (din) state_next = S1;
                else      state_next = S0;
            end
            S1: begin
                if (din) state_next = S1;
                else      state_next = S2;
            end
            S2: begin
                if (din) state_next = S3;
                else      state_next = S0;
            end
            S3: begin
                if (din) state_next = S1;
                else      state_next = S2;
            end
            default: state_next = S0;
        endcase
    end

    // Output Logic (Moore)
    always @(*) begin
        case (state_reg)
                        S0: q_out = 1'b0;
                        S1: q_out = 1'b0;
                        S2: q_out = 1'b0;
                        S3: q_out = 1'b1;
            default: q_out = 1'b0;
        endcase
    end

endmodule

