107. Vending Machine FSM.rtl:
module vending_fsm(
    input clk,
    input rst,
    input nickel,
    input dime,
    output reg dispense
);
    localparam S0  = 2'd0;
    localparam S5  = 2'd1;
    localparam S10 = 2'd2;
    localparam S15 = 2'd3;

    reg [1:0] state, next_state;

    always @(posedge clk or posedge rst) begin
        if (rst) state <= S0;
        else     state <= next_state;
    end

    always @(*) begin
        dispense = (state == S15);
        case (state)
            S0: begin
                if (dime)        next_state = S10;
                else if (nickel) next_state = S5;
                else             next_state = S0;
            end
            S5: begin
                if (dime)        next_state = S15;
                else if (nickel) next_state = S10;
                else             next_state = S5;
            end
            S10: begin
                if (dime || nickel) next_state = S15;
                else                next_state = S10;
            end
            S15: next_state = S0;
            default: next_state = S0;
        endcase
    end
endmodule

