module fifo_fsm(
    input clk,
    input rst,
    input wr,
    input rd,
    output reg full,
    output reg empty
);
    reg [2:0] count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 0;
        end else begin
            case ({wr, rd})
                2'b10: if (count < 3'd4) count <= count + 1;
                2'b01: if (count > 0)    count <= count - 1;
                default: ;
            endcase
        end
    end

    always @(*) begin
        full = (count == 3'd4);
        empty = (count == 0);
    end
endmodule

