109. GCD Controller.rtl:
module gcd_ctrl(
    input clk,
    input rst,
    input start,
    input [7:0] a_in,
    input [7:0] b_in,
    output reg [7:0] gcd_out,
    output reg done
);
    localparam IDLE = 2'd0;
    localparam COMPUTE = 2'd1;
    localparam DONE = 2'd2;

    reg [1:0] state;
    reg [7:0] a, b;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            gcd_out <= 0;
            done <= 0;
        end else begin
            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                          a <= a_in;
                          b <= b_in;
                          state <= COMPUTE;
                    end
                end
                COMPUTE: begin
                    if (a == b) begin
                          gcd_out <= a;
                          done <= 1;
                          state <= DONE;
                    end else if (a > b) begin
                          a <= a - b;
                    end else begin
                          b <= b - a;
                    end
                end
                DONE: begin
                    done <= 0;
                    state <= IDLE;
                end
            endcase
        end
    end
endmodule

